.kanban-columns {
  display: flex;
  gap: 16px;
  overflow-x: auto;
  padding: 16px 0;
  height: calc(100vh - 120px);
  align-items: flex-start;
}
/* Column width */
.kanban-column {
  min-width: 280px;
  width: 25%;
  max-width: 360px;
  background-color: var(--md-surface-container);
  border-radius: var(--md-sys-shape-corner-medium);
  padding: 16px;
  box-shadow: var(--md-sys-elevation-level-0);
}
