    // Load or initialize synced board state
    async function initBoard() {
      populateDropdowns();

      if (envId) {
        document.getElementById("syncStatus").style.display = "flex";
        document.getElementById("syncText").textContent = "Live Syncing";
        document.getElementById("syncDot").className = "sync-dot syncing";
        await loadSyncedState();
        setInterval(loadSyncedState, 2000);
      } else {
        // Fallback to localStorage for frictionless local performance
        document.getElementById("syncStatus").style.display = "flex";
        document.getElementById("syncText").textContent = "Local Space Storage";
        document.getElementById("syncDot").className = "sync-dot offline";

        const localData = localStorage.getItem(syncKey);
        if (localData) {
          try {
            state = JSON.parse(localData);
          } catch (e) {
            console.error("Local parse failed, resorting to seed data", e);
            state.tasks = [...defaultTasks];
          }
        } else {
          state.tasks = [...defaultTasks];
          localStorage.setItem(syncKey, JSON.stringify(state));
        }
        renderBoard();
      }
    }

    // Sync Load Handler
    async function loadSyncedState() {
      if (!envId) return;
      try {
        const res = await fetch(`/api/sync/${envId}/${syncKey}`);
        const json = await res.json();
        if (json.data && json.data.tasks) {
          state = json.data;
          renderBoard();
        } else {
          // If server state is fresh and empty, populate with template default data
          state.tasks = [...defaultTasks];
          await saveSyncedState(state);
          renderBoard();
        }
      } catch (err) {
        console.error("Failed to load synced state:", err);
      }
    }

    // Sync Save Handler
    async function saveSyncedState(newState) {
      if (envId) {
        try {
          await fetch(`/api/sync/${envId}/${syncKey}`, {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ data: newState })
          });
        } catch (err) {
          console.error("Failed to save synced state:", err);
        }
      } else {
        localStorage.setItem(syncKey, JSON.stringify(newState));
      }
    }

    // UI Render Board
    function renderBoard() {
      const currentStr = JSON.stringify(state);
      // Skip redundant refactoring if nothing has changed (prevent cursor jumps / flickering)
      if (currentStr === lastRenderedStateString) {
        return;
      }
      lastRenderedStateString = currentStr;

      // Filter text criteria
      const searchText = document.getElementById("searchInput").value.toLowerCase();
      const filterAssigneeVal = document.getElementById("filterAssignee").value;

      const columns = {
        'todo': document.getElementById("list-todo"),
        'in-progress': document.getElementById("list-in-progress"),
        'review': document.getElementById("list-review"),
        'done': document.getElementById("list-done")
      };

      // Reset column layouts
      for (let colKey in columns) {
        columns[colKey].innerHTML = "";
      }

      const columnCounts = { 'todo': 0, 'in-progress': 0, 'review': 0, 'done': 0 };

      state.tasks.forEach(task => {
        // Apply priority criteria
        if (activePriorityFilter !== 'All' && task.priority !== activePriorityFilter) {
          return;
        }

        // Apply assignee criteria
        if (filterAssigneeVal !== 'All') {
          if (filterAssigneeVal === "" && task.assignee) return;
          if (filterAssigneeVal !== "" && task.assignee !== filterAssigneeVal) return;
        }

        // Apply search input query
        if (searchText) {
          const matchTitle = task.title.toLowerCase().includes(searchText);
          const matchDesc = (task.description || "").toLowerCase().includes(searchText);
          const matchAssignee = (task.assignee || "").toLowerCase().includes(searchText);
          const matchPriority = task.priority.toLowerCase().includes(searchText);
          if (!matchTitle && !matchDesc && !matchAssignee && !matchPriority) {
            return;
          }
        }

        // Increment count
        if (columnCounts.hasOwnProperty(task.column)) {
          columnCounts[task.column]++;
        }

        // Card Element Builder
        const card = document.createElement("div");
        card.className = "task-card";
        card.id = `card-${task.id}`;
        card.draggable = true;
        card.ondragstart = (e) => handleDragStart(e, task.id);
        card.ondragend = (e) => handleDragEnd(e);
        card.onclick = (e) => handleCardClick(e, task);

        // Header priorities
        const priorityClass = `priority-${task.priority.toLowerCase()}`;

        // Avatar generation
        const initials = getInitials(task.assignee);
        const avatarBg = getAvatarColor(task.assignee);

        card.innerHTML = `
          <div class="card-top">
            <span class="priority-badge ${priorityClass}">${task.priority}</span>
            <div class="card-actions">
              <button class="action-icon-btn" onclick="toggleMoveMenu(event, '${task.id}')">
                <span class="material-icons-outlined" style="font-size: 18px;">swap_horiz</span>
              </button>
              <div class="quick-move-menu" id="menu-${task.id}">
                <div class="quick-move-item" onclick="quickMoveTask(event, '${task.id}', 'todo')"><span class="material-icons-outlined" style="font-size: 14px;">arrow_forward</span> To Do</div>
                <div class="quick-move-item" onclick="quickMoveTask(event, '${task.id}', 'in-progress')"><span class="material-icons-outlined" style="font-size: 14px;">arrow_forward</span> In Progress</div>
                <div class="quick-move-item" onclick="quickMoveTask(event, '${task.id}', 'review')"><span class="material-icons-outlined" style="font-size: 14px;">arrow_forward</span> Under Review</div>
                <div class="quick-move-item" onclick="quickMoveTask(event, '${task.id}', 'done')"><span class="material-icons-outlined" style="font-size: 14px;">arrow_forward</span> Done</div>
              </div>
            </div>
          </div>
          <div class="task-title">${escapeHTML(task.title)}</div>
          ${task.description ? `<div class="task-desc">${escapeHTML(task.description)}</div>` : ''}
