    // Avatar visual helpers
    function getInitials(name) {
      if (!name) return "?";
      const parts = name.trim().split(/\s+/);
      if (parts.length >= 2) {
        return (parts[0][0] + parts[parts.length - 1][0]).toUpperCase();
      }
      return name.slice(0, 2).toUpperCase();
    }

    function getAvatarColor(name) {
      if (!name) return "#e0e0e0";
      let hash = 0;
      for (let i = 0; i < name.length; i++) {
        hash = name.charCodeAt(i) + ((hash << 5) - hash);
      }
      // Clean Workspace pastel colors
      const h = Math.abs(hash) % 360;
      return `hsl(${h}, 65%, 82%)`;
    }

    // HTML sanitizer
    function escapeHTML(str) {
      if (!str) return '';
      return str.replace(/[&<>'"]/g, 
        tag => ({ '&': '&amp;', '<': '&lt;', '>': '&gt;', "'": '&#39;', '"': '&quot;' }[tag] || tag)
      );
    }

    // HTML5 Drag and Drop Handlers
    let activeDraggedTaskId = null;

    function handleDragStart(e, taskId) {
      activeDraggedTaskId = taskId;
      const card = document.getElementById(`card-${taskId}`);
      if (card) {
        card.classList.add("dragging");
      }
      e.dataTransfer.setData("text/plain", taskId);
    }

    function handleDragEnd(e) {
      if (activeDraggedTaskId) {
        const card = document.getElementById(`card-${activeDraggedTaskId}`);
        if (card) {
          card.classList.remove("dragging");
        }
      }
      activeDraggedTaskId = null;
    }

    function allowDrop(e) {
      e.preventDefault();
    }

    function dragEnter(e) {
      e.preventDefault();
      const col = e.currentTarget;
      col.classList.add("drag-over");
    }

    function dragLeave(e) {
      const col = e.currentTarget;
      col.classList.remove("drag-over");
    }

    async function handleDrop(e, targetColumn) {
      e.preventDefault();
      const col = e.currentTarget;
      col.classList.remove("drag-over");

      const taskId = e.dataTransfer.getData("text/plain") || activeDraggedTaskId;
      if (!taskId) return;

      const taskIndex = state.tasks.findIndex(t => t.id === taskId);
      if (taskIndex !== -1 && state.tasks[taskIndex].column !== targetColumn) {
        state.tasks[taskIndex].column = targetColumn;
        renderBoard();
        await saveSyncedState(state);
      }
    }

    // Quick move menus support (click alternatives for drag/drop)
    function toggleMoveMenu(e, taskId) {
      e.stopPropagation();
      // Close all other menus first
      document.querySelectorAll(".quick-move-menu").forEach(menu => {
        if (menu.id !== `menu-${taskId}`) menu.classList.remove("open");
      });
      const menu = document.getElementById(`menu-${taskId}`);
      menu.classList.toggle("open");
    }

    async function quickMoveTask(e, taskId, targetColumn) {
      e.stopPropagation();
      const menu = document.getElementById(`menu-${taskId}`);
      if (menu) menu.classList.remove("open");

      const taskIndex = state.tasks.findIndex(t => t.id === taskId);
      if (taskIndex !== -1) {
        state.tasks[taskIndex].column = targetColumn;
        renderBoard();
        await saveSyncedState(state);
      }
    }

    // Close any popup overlay clicks elsewhere
    window.addEventListener("click", () => {
      document.querySelectorAll(".quick-move-menu").forEach(menu => {
        menu.classList.remove("open");
