    // Modal Interaction
    function openAddTaskModal(column = 'todo') {
      document.getElementById("dialogTitle").textContent = "Add New Task";
      document.getElementById("editTaskId").value = "";
      document.getElementById("taskInputTitle").value = "";
      document.getElementById("taskInputDesc").value = "";
      document.getElementById("taskInputAssignee").value = "";
      document.getElementById("taskInputColumn").value = column;
      document.getElementById("taskInputPriority").value = "Medium";
      document.getElementById("deleteBtn").style.display = "none";

      const modal = document.getElementById("taskDialog");
      modal.classList.add("open");
    }

    function handleCardClick(e, task) {
      // Prevent dialog open on utility menu clicks
      if (e.target.closest('.card-actions')) return;

      document.getElementById("dialogTitle").textContent = "Edit Task";
      document.getElementById("editTaskId").value = task.id;
      document.getElementById("taskInputTitle").value = task.title;
      document.getElementById("taskInputDesc").value = task.description || "";
      document.getElementById("taskInputAssignee").value = task.assignee || "";
      document.getElementById("taskInputColumn").value = task.column;
      document.getElementById("taskInputPriority").value = task.priority;
      document.getElementById("deleteBtn").style.display = "block";

      const modal = document.getElementById("taskDialog");
      modal.classList.add("open");
    }

    function closeDialog() {
      document.getElementById("taskDialog").classList.remove("open");
    }

    // Task Create / Edit Save action
    async function saveTask() {
      const id = document.getElementById("editTaskId").value;
      const title = document.getElementById("taskInputTitle").value.trim();
      const description = document.getElementById("taskInputDesc").value.trim();
      const assignee = document.getElementById("taskInputAssignee").value;
      const column = document.getElementById("taskInputColumn").value;
      const priority = document.getElementById("taskInputPriority").value;

      if (!title) {
        alert("Task title is required.");
        return;
      }

      if (id) {
        // Edit flow
        const taskIndex = state.tasks.findIndex(t => t.id === id);
        if (taskIndex !== -1) {
          state.tasks[taskIndex] = {
            ...state.tasks[taskIndex],
            title,
            description,
            assignee,
            column,
            priority
          };
        }
      } else {
        // Add flow
        const newTask = {
          id: 'task_' + Date.now(),
          title,
          description,
          assignee,
          column,
          priority,
          createdAt: new Date().toISOString()
        };
        state.tasks.push(newTask);
      }

      closeDialog();
      renderBoard();
      await saveSyncedState(state);
    }

    // Task Delete action
    async function deleteTask() {
      const id = document.getElementById("editTaskId").value;
      if (!id) return;

      if (confirm("Are you sure you want to delete this task?")) {
        state.tasks = state.tasks.filter(t => t.id !== id);
        closeDialog();
        renderBoard();
        await saveSyncedState(state);
      }
    }

    // Start App Setup
    window.addEventListener("DOMContentLoaded", initBoard);
  </script>
